public struct BuffInfo
{
    public List<ActorRef<Card>> targetCards;
    public List<ActorRef<Hero>> targetHeroes;
    public string buffEffect;
}

private Dictionary<ActorRef<Card>, List<BuffInfo>> m_bufferCards = new();

public void RecordBuff(ActorRef<Card> buffCard, List<ActorRef<Card>> targetCards, string buffEffect)
{
    // 如果卡牌从来没有buff过则新增一条记录
    if (!m_bufferCards.ContainsKey(buffCard))
    {
        var buffInfo = new BuffInfo
        {
            targetCards = targetCards,
            buffEffect = buffEffect
        };
        var buffInfos = new List<BuffInfo>
        {
            buffInfo
        };
        m_bufferCards.Add(buffCard, buffInfos);
        return;
    }

    var existInfos = m_bufferCards[buffCard];
    bool isExistEffect = existInfos.Exists(info => info.buffEffect.Equals(buffEffect));
    if (isExistEffect)
    {
        foreach (var existBuffInfo in existInfos)
        {
            if (existBuffInfo.buffEffect.Equals(buffEffect))
            {
                foreach (var targetCard in targetCards.Where(targetCard =>
                             !existBuffInfo.targetCards.Contains(targetCard)))
                {
                    existBuffInfo.targetCards.Add(targetCard);
                }
            }
        }
    }
    else
    {
        var buffInfo = new BuffInfo
        {
            targetCards = targetCards,
            buffEffect = buffEffect
        };
        existInfos.Add(buffInfo);
    }
