using System.Collections.Generic;
using System.Linq;

public struct BuffInfo
{
    public HashSet<ActorRef<Card>> targetCards; // 如果目标卡片唯一性很重要，使用HashSet提高搜索效率
    public string buffEffect;
}

private Dictionary<ActorRef<Card>, List<BuffInfo>> m_bufferCards = new();

public void RecordBuff(ActorRef<Card> buffCard, List<ActorRef<Card>> targetCards, string buffEffect)
{
    // 如果卡牌从来没有buff过则新增一条记录
    if (!m_bufferCards.TryGetValue(buffCard, out var existInfos))
    {
        var buffInfo = new BuffInfo
        {
            targetCards = new HashSet<ActorRef<Card>>(targetCards), // 直接构造HashSet
            buffEffect = buffEffect
        };
        m_bufferCards.Add(buffCard, new List<BuffInfo> { buffInfo });
        return;
    }

    // 查找是否已有相同buffEffect的BuffInfo
    var buffInfo = existInfos.FirstOrDefault(info => info.buffEffect.Equals(buffEffect));
    if (buffInfo.Equals(default(BuffInfo)))
    {
        // 不存在相同效果则添加新的BuffInfo
        existInfos.Add(new BuffInfo
        {
            targetCards = new HashSet<ActorRef<Card>>(targetCards),
            buffEffect = buffEffect
        });
    }
    else
    {
        // 存在相同效果则向targetCards添加新目标卡牌，使用UnionWith因为targetCards已经是HashSet
        buffInfo.targetCards.UnionWith(targetCards);
    }
}
